const polygonRendering = (
    source: SourceSpecification,
    layerName: string,
    sourceName: string,
    map: MaplibreMap
) => {

    map.on("removePolygon", () => {
        if (map.getLayer(layerName)) {
            map.removeLayer(layerName);
        }

        if (map.getLayer(`${sourceName}-border`)) {
            map.removeLayer(`${sourceName}-border`);
        }

        if (map.getSource('polygonOutlineSource')) {
            map.removeSource('polygonOutlineSource')
        }

        if (map.getSource('polygonSource')) {
            map.removeSource('polygonSource')
        }
    })

    map.fire("removePolygon")
    map.addSource('polygonOutlineSource', source);
    map.addSource('polygonSource', source);

    map.addLayer({
        "id": "polygonLayer",
        "type": "fill",
        "source": "polygonSource",
        "layout": {},
        "paint": {
            "fill-color": "#1976D2",
            "fill-opacity": 0.1,
        }
    });

    map.addLayer(
        {
            'id': 'polygonOutline',
            'type': 'line',
            'source': 'polygonOutlineSource',
            'layout': {
                "line-join": "round",
                "line-cap": "round",
            },
            'paint': {
                'line-color': '#1976D2',
                'line-width': 1,
            },
        }
    );
}
